namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.Add(new Notification(_nextId++, "Welcome to the notifications page!", DateTime.UtcNow.AddMinutes(-10)));
        _notifications.Add(new Notification(_nextId++, "Your profile was updated successfully.", DateTime.UtcNow.AddMinutes(-5)));
        _notifications.Add(new Notification(_nextId++, "New feature: dark mode is now available.", DateTime.UtcNow.AddMinutes(-2)));
    }

    /// <summary>
    /// Returns all notifications known so far.
    /// </summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return _notifications.ToList();
        }
    }

    /// <summary>
    /// Returns only notifications with an Id greater than <paramref name="sinceId"/>.
    /// </summary>
    public List<Notification> GetSince(int sinceId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > sinceId).ToList();
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Called internally by a background hosted service.
    /// </summary>
    public void AddRandom()
    {
        var messages = new[]
        {
            "You have a new follower!",
            "Your post received a like.",
            "Server maintenance scheduled for tonight.",
            "New comment on your article.",
            "Your subscription is expiring soon.",
            "A friend just joined the platform!",
            "Weekly summary is ready to view."
        };

        lock (_lock)
        {
            var msg = messages[Random.Shared.Next(messages.Length)];
            _notifications.Add(new Notification(_nextId++, msg, DateTime.UtcNow));
        }
    }
}

namespace BlazorNotifications.Services;

/// <summary>
/// Background service that periodically generates fake notifications
/// to simulate real-time data arriving.
/// </summary>
public class NotificationGeneratorService : BackgroundService
{
    private readonly NotificationService _notificationService;

    public NotificationGeneratorService(NotificationService notificationService)
    {
        _notificationService = notificationService;
    }

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(8), stoppingToken);
            _notificationService.AddRandom();
        }
    }
}

