@page "/notifications"
@rendermode InteractiveServer
@using BlazorNotifications.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    <span class="badge bg-primary rounded-pill ms-2">@notifications.Count</span>
</h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> notifications = new();
    private CancellationTokenSource? _cts;

    // Loads initial data during prerender AND interactive render.
    // On the interactive render the same data is reused via the condition below.
    protected override void OnInitialized()
    {
        notifications = NotificationService.GetAll();
    }

    // Called only once after the component is interactive in the browser.
    // This is where we start the polling loop — it will NOT run during static SSR.
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        // Track the highest Id we already have so we only fetch new ones
        var lastId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;

        while (!cancellationToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken);

            var newItems = NotificationService.GetSince(lastId);
            if (newItems.Count > 0)
            {
                notifications.AddRange(newItems);
                lastId = newItems.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

